arguments.argument:
if global.gamePaused=false
{
  if instrProg=0
  {
    image_alpha+=0.02
    if image_alpha=1
    {
      activeTime=500+(image_index*180)
      instrProg+=1
    }
  }
  else if instrProg=1
  {
    if bCanTakeDamage=0
    {
      activeTime-=1
      if activeTime<=0 {bCanTakeDamage=1}
    }
  }
}
